interface IconProps {
  name: string;
  className?: string;
  size?: number;
  "aria-hidden"?: boolean | "true" | "false";
}

export default function Icon({ name, className = "", size = 24, ...props }: IconProps) {
  const path = paths[name];
  if (!path) return null;
  return (
    <svg
      xmlns="http://www.w3.org/2000/svg"
      viewBox="0 0 24 24"
      width={size}
      height={size}
      fill="currentColor"
      className={className}
      dangerouslySetInnerHTML={{ __html: path }}
      {...props}
    />
  );
}
